def main(doc):
    def get_date_ranges(attendance_start_date, relieving_date):
        fiscal_years = frappe.db.get_all(
            "Fiscal Year", 
            {"year_start_date": ("between", [attendance_start_date, relieving_date])}, 
            ["year_start_date", "year_end_date"],
        )
        return fiscal_years

    def get_non_working_days(status, start_date, end_date):
        filters = {
    		"docstatus": 1,
    		"status": doc.status,
    		"employee": doc.employee,
    		"attendance_date": ("between", [start_date, end_date]),
    	}

        if status == "On Leave":
            lwp_leave_types = frappe.get_all("Leave Type", filters={"is_lwp": 1}, pluck="name")
            filters["leave_type"] = ("IN", lwp_leave_types)

        record = frappe.get_all("Attendance", filters=filters, fields=["COUNT(*) as total_lwp"])
        frappe.throw(f"{record[0].total_lwp}")
        return record[0].total_lwp if len(record) else 0

    def get_working_days(start_date, end_date):
        total_working_days = (frappe.utils.get_datetime(end_date) - frappe.utils.get_datetime(start_date)).days

        payroll_based_on = frappe.db.get_single_value("Payroll Settings", "payroll_based_on") or "Leave"
        if payroll_based_on == "Leave":
        	total_lwp = get_non_working_days("On Leave", start_date, end_date)
        	total_working_days = total_working_days - total_lwp
        elif payroll_based_on == "Attendance":
        	total_absent_days = get_non_working_days("Absent", start_date, end_date)
        	total_working_days = total_working_days - total_absent_days

        return total_working_days

    def calculate_work_experience():
        REQUIRED_DAYS_PER_YEAR = 220

        # from Attendance History
        method = frappe.db.get_value("Gratuity Rule", doc.gratuity_rule, "work_experience_calculation_function")
        if method != "Manual":
            return

        years_of_experience = 0
        record = frappe.db.get_value("Attendance History", {"employee": doc.employee}, "name")
        if record:
            history = frappe.get_doc("attendance_history", record)
            for entry in history.attendance_history:
                if frappe.utils.flt(entry.actual_working_days) > REQUIRED_DAYS_PER_YEAR:
                    years_of_experience = years_of_experience + 1

        # from actual attendance records
        ACTUAL_ATTENDANCE_CUTOFF_DATE = frappe.utils.getdate("01/04/2023", parse_day_first=True)
        dates = frappe.db.get_value("Employee", doc.employee, ["date_of_joining", "relieving_date"], as_dict=True)
        date_of_joining = dates.date_of_joining
        relieving_date = dates.relieving_date

        if not relieving_date:
    	    frappe.throw(f"Please set the relieving date for employee {frappe.utils.get_link_to_form('Employee', doc.employee)}")

        date_ranges = get_date_ranges(ACTUAL_ATTENDANCE_CUTOFF_DATE, relieving_date)
        for dt in date_ranges:
            start_date = dt.year_start_date
            if start_date < date_of_joining and date_of_joining < end_date:
                start_date = date_of_joining

            end_date = dt.year_end_date
            if start_date < relieving_date and relieving_date < end_date:
                end_date = relieving_date

            if get_working_days(start_date, end_date) > REQUIRED_DAYS_PER_YEAR:
                years_of_experience = years_of_experience + 1

        doc.current_work_experience = years_of_experience
        frappe.throw(f"{years_of_experience}")
    calculate_work_experience()

