def main(doc):
	def get_arrear_component(salary_component):
		arrear_component = frappe.db.exists("Salary Component", f"Arrear {salary_component}")
		if arrear_component:
			return arrear_component

		salary_component_doc = frappe.get_doc("Salary Component", salary_component)
		arrear_component_doc = frappe.copy_doc(salary_component_doc)
		arrear_component_doc.salary_component = f"Arrear {salary_component_doc.name}"
		arrear_component_doc.salary_component_abbr = f"ARR_{salary_component_doc.salary_component_abbr}"
		arrear_component_doc.save()
		return arrear_component_doc.name

	def set_actual_payment_days_and_working_hours(salary_slip):
		doc.actual_payment_days = salary_slip.payment_days
		doc.actual_working_hours = salary_slip.actual_working_hours

	def set_arrears_details(salary_slip, recalculated_salary_slip):
		for d in ["earnings", "deductions"]:
			for detail in recalculated_salary_slip.get(d):
				arrear_component = get_arrear_component(detail.salary_component)
				original_component = salary_slip.get(
					d, {"salary_component": detail.salary_component}
				)
				original_amount = original_component[0].amount if original_component else 0
				difference = detail.amount - original_amount
				doc.append(
					d,
					{
						"component": arrear_component,
						"new_amount": detail.amount,
						"difference_in_amount": difference,
					},
				)

	def handle_calculation_errors_in_previous_months():
		doc.earnings = []
		doc.deductions = []
		salary_slip = frappe.get_doc("Salary Slip", doc.salary_slip)
		recalculated_salary_slip = frappe.copy_doc(salary_slip)
		recalculated_salary_slip.run_method("validate")
		set_actual_payment_days_and_working_hours(recalculated_salary_slip)
		set_arrears_details(salary_slip, recalculated_salary_slip)

	def handle_salary_revision():
		doc.earnings = []
		doc.deductions = []
		salary_slips = frappe.get_all(
			"Salary Slip",
			{
				"employee": doc.employee,
				"start_date": ["between", [doc.from_date, doc.to_date]],
			},
			pluck="name",
		)
		for salary_slip in salary_slips:
			salary_slip = frappe.get_doc("Salary Slip", salary_slip)
			revised_salary_slip = frappe.copy_doc(salary_slip)
			revised_salary_slip.salary_structure = doc.revised_salary_structure
			revised_salary_slip.calculate_net_pay()
			revised_salary_slip.compute_year_to_date()
			revised_salary_slip.compute_month_to_date()
			revised_salary_slip.compute_component_wise_year_to_date()
			revised_salary_slip.run_method("validate")
			set_arrears_details(salary_slip, revised_salary_slip)

	if doc.process_arrears_for == "Calculation Errors in Previous Months":
		handle_calculation_errors_in_previous_months()
	else:
		handle_salary_revision()


