# Function to rename old BOMs by appending " - DNU"
def rename_old_boms(input_boms):
    old_bom_data = [
        {"old_bom": bom[:-3] + "001", "new_bom": bom[:-3] + "001" + " - DNU"}
        for bom in input_boms
    ]
    
    for item in old_bom_data:
        if frappe.db.exists('BOM', item['old_bom']):
            frappe.rename_doc('BOM', item['old_bom'], item['new_bom'])
            frappe.msgprint(f"Document renamed from {item['old_bom']} to {item['new_bom']}", 
                            alert=True, indicator="green")
        else:
            frappe.throw(f"Old BOM {item['old_bom']} not found")


# Function to rename current BOMs to a new BOM format
def rename_new_boms(input_boms):
    new_bom_data = [
        {"old_bom": bom, "new_bom": bom[:-3] + "001"}
        for bom in input_boms
    ]
    
    for item in new_bom_data:
        if frappe.db.exists('BOM', item['old_bom']):
            frappe.rename_doc('BOM', item['old_bom'], item['new_bom'])
            frappe.msgprint(f"Document renamed from {item['old_bom']} to {item['new_bom']}", 
                            alert=True, indicator="green")
        else:
            frappe.throw(f"New BOM {item['old_bom']} not found")

