    if doc.company == 'Gurukrupa Export Private Limited':
        company_abbr = '- GEPL'
    if doc.company == 'KG GK Jewellers Private Limited':
        company_abbr = '- KGJPL'
    if doc.company == 'Sadguru Diamond':
        company_abbr = '- SD'
    if doc.company == 'Sadguru Hallmarking Centre':
        company_abbr = '- SHC'
    if doc.company == 'Test_Company':
        company_abbr = '- TC'
    # order = {
    #     "Input Tax CGST - GEPL": 0,
    #     "Input Tax SGST - GEPL": 1,
    #     "Input CGST RCM - GEPL": 2,
    #     "Input SGST RCM - GEPL": 3
    # }
    account_list = []
    if doc.items:
        doc.taxes=[]
        for i in doc.items:

            item_tax_template = frappe.db.sql(f"""select item_tax_template from `tabItem Tax` where  parent = '{i.item_code}' and item_tax_template LIKE '%{company_abbr}'""",as_dict=1)
            # frappe.throw(f"{item_tax_template}")
            if item_tax_template:
                if item_tax_template[0]['item_tax_template'] not in ['Exempted - GEPL','Exempted - KGJPL', 'Exempted - SHC', 'Exempted - SD']:

                    i.item_tax_template = item_tax_template[0]['item_tax_template']
                    i.gst_treatment = 'Taxable'
                    if doc.tax_category == 'In-State':
                        if not doc.is_reverse_charge:
                            tax = frappe.db.sql(f"select tax_type,tax_rate from `tabItem Tax Template Detail` where parent = '{item_tax_template[0]['item_tax_template']}' and tax_type NOT LIKE '%IGST%' and tax_type LIKE 'Input%' and tax_type NOT LIKE '%RCM%'", as_dict=1)
                        else:
                            tax = frappe.db.sql(f"select tax_type,tax_rate from `tabItem Tax Template Detail` where parent = '{item_tax_template[0]['item_tax_template']}' and (tax_type LIKE '%RCM%' or tax_type LIKE 'Input%' and tax_type not LIKE 'Output%') and tax_type NOT LIKE '%IGST%'", as_dict=1)
                    else:
                        if not doc.is_reverse_charge:
                            tax = frappe.db.sql(f"select tax_type,tax_rate from `tabItem Tax Template Detail` where parent = '{item_tax_template[0]['item_tax_template']}' and tax_type LIKE '%IGST%' and tax_type LIKE 'Input%' and tax_type NOT LIKE '%RCM%'", as_dict=1)
                        else:
                            tax = frappe.db.sql(f"select tax_type,tax_rate from `tabItem Tax Template Detail` where parent = '{item_tax_template[0]['item_tax_template']}' and (tax_type LIKE '%RCM%' or tax_type LIKE 'Input%') and tax_type LIKE '%IGST%'", as_dict=1)
                    for j in tax:
                        # if j.get("tax_type") in account_list and len(doc.items)<1:
                        if j.get("tax_type") in account_list:
                            continue
                        account_list.append(j.get("tax_type"))
                        if 'IGST' in j.get("tax_type"):
                            gst_tax_type = 'igst'
                        if 'SGST' in j.get("tax_type"):
                            gst_tax_type = 'sgst'
                        if 'CGST' in j.get("tax_type"):
                            gst_tax_type = 'cgst'
                        if 'IGST RCM' in j.get("tax_type"):
                            gst_tax_type = 'igst_rcm'
                        if 'SGST RCM' in j.get("tax_type"):
                            gst_tax_type = 'sgst_rcm'
                        if 'CGST RCM' in j.get("tax_type"):
                            gst_tax_type = 'cgst_rcm'

                        if 'RCM' in j.get("tax_type"):
                            add_deduct_tax = "Deduct"
                        else:
                            add_deduct_tax = "Add"
                        doc.append("taxes", {
                            "category": "Total",
                            "add_deduct_tax": add_deduct_tax,
                            "charge_type": "On Net Total",
                            "account_head": j.get("tax_type"),
                            "description": j.get("tax_type").replace(" - GE", ""),
                            "rate": j.get("tax_rate"),
                            "gst_tax_type":gst_tax_type
                        })
